INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('7552d248-d646-44dc-92ce-7b3c5c7749d0', NULL, 'Facma selfpropelled harvester C380S', 'Facma C380S თვითმავალი მოსავლის ამღები კომბაინი (ნიადაგიდან)', '<ul><li>Self-propelled harvester for almonds, hazelnuts and walnuts</li><li>Machine suitable for local “Anakliuri” variety</li><li>Up to 2-3 tons/hour harvesting capacity</li><li>Combination of mechanical collecting system and vacuum to harvest also in difficult land conditions</li><li>Easy maintenance</li><li>Service 24/7 available in Georgia</li></ul>', '<ul><li>თვითმავალი კომბაინი ნუშის, თხილის და კაკლისთვის</li><li>კომბაინი შესაფერისია ადგილობრივი „ანაკლიურის“ ჯიშისთვის</li><li>წარმადობა: 2-3 ტონა საათში</li><li>მექანიკური და ვაკუუმის სისტემები,&nbsp;რთულ რელიეფზე სამუშაოდ</li><li>მარტივი მოვლა და ტექნიკური მომსახურება</li><li>24/7 მომსახურება ხელმისაწვდომია საქართველოში</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/9288d1fb-b5ad-48fd-9c76-a79c2bdb847e.webp', 'https://www.facebook.com/watch/?v=451793224141793', NULL, false, '2025-11-08T09:41:03.022348+00:00', '2025-11-11T12:56:03.740922+00:00', 'facma-selfpropelled-harvester', 'facma-c380s-thvithmavali-mosatslis-amghebi', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/3524ed0a-6a55-4450-a667-9be2d825959e.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/49cbfc52-7535-4353-a7a8-95fb9951a4a1.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/f7c9099e-1336-4365-a15a-b2685ad8b686.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('d2b700cd-0ee7-4c9b-9661-3a034e272e75', '9c4776ab-9235-4817-84b0-7ab17c478cc3', 'Inter-row eco trimmer', 'მწკრივთა შორის სათიბი', '<ul><li>Perfect to remove grass between trees without using chemicals</li><li>3 points rear frame with 3 stabilizing wheels, hydraulic system</li><li>Eco trimmer 2/300: opening from 190 to 300 cm</li><li>Eco trimmer 2/420: opening from 260 to 420 cm</li></ul>', '<ul><li>იდეალურია ბალახის მოსაშორებლად ხეების შორის, ჰერბიციდის გარეშე</li><li>3-წერტილოვანი უკანა ჩარჩო 3 სტაბილიზატორ თვლით (ჰიდრავლიკური სისტემა)</li><li>Eco Trimmer 2/300: განშორება 190-დან 300 სმ-მდე</li><li>Eco Trimmer 2/420: განშორება 260-დან 420 სმ-მდე</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/8af13596-05bd-47ae-8ce7-0b0aebcaab30.webp', 'https://youtube.com/shorts/91e_W4RVCUM?si=Rl-91Jk6kxWvy3ES', NULL, false, '2025-11-05T18:12:06.737513+00:00', '2025-11-12T12:17:10.922389+00:00', 'inter-row-eco-trimmer', 'mtskrivta-shoris-eko-trimeri', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/38c8a032-aadf-4f3f-ba9e-c14fb012b5f2.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('87e70e16-d2fc-489e-8a79-25b13d0d0a8d', NULL, 'Self-propelled shaker Red Devil', 'თვითმავალი აგრეგატი Red Devil', '<ul><li>Suitable for almonds and walnuts big plantations</li><li>4-wheel drive, two steering axles, three types of steering</li><li>Transmission: two-speed hydraulic</li><li>IVECO 126HP engine</li><li>420 bar hydraulic pump (average in the market is 280 bar)</li><li>Can shake trees up to 60 cm diameter</li><li>Possibility to install umbrella system</li></ul>', '<ul><li>ნუშისა და კაკლის დიდი პლანტაციებისთვის</li><li>ორი ხიდიანი მართვის სიტემა, მართვის სამი ტიპი</li><li>გადაცემათა კოლოფი: ორ სიჩქარიანი ჰიდრავლიკური</li><li>IVECO ძრავა — 126 ცხენის ძალა</li><li>ჰიდრავლიკური ტუმბო — 420 ბარი </li><li>შესაძლებელია 60 სმ დიამეტრის მქონე ხეების დარხევა</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/8669b888-b5ec-4b63-a542-46533d3aa35b.webp', 'https://youtu.be/lsSNMcaNKoI', NULL, false, '2025-11-07T14:03:47.929109+00:00', '2025-11-07T14:03:47.929109+00:00', 'self-propelled-shaker-red-devil', 'thvithmavali-agregati-red-devil', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/7983896c-01d4-4da8-a934-49fc92990987.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/466bb85d-a503-424e-816e-a0f224c3429d.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/9c628e7a-0183-4d53-b189-cfbd7b19a0df.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('84516a89-fb8e-4640-9212-ce40c0339810', NULL, 'GF Superjolly', 'GF-ტრაქტორზე ასაკიდებელი მოსავლის ამღები', '<ul><li>Mechanical harvester to attach to tractor</li><li>Available in different sizes from 1.5 to 2.8 meters width</li><li>Product cleaning and dehusking inside the machine</li><li>Up to 500 kg/hour harvesting capacity</li></ul>', '<ul><li>მექანიკური მოსავალი ამღები&nbsp;</li><li>ხელმისაწვდომია სხვადასხვა ზომებში, სიგანით 1.5-დან 2.8 მეტრამდე</li><li>პროდუქტის წმენდა და გასუფთავება აგრეგატის შიგნით</li><li>წარმადობა: 500 კგ საათში</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/042a6900-445a-402c-a473-3b58098bdc4c.webp', 'https://youtu.be/qN4W8AqEx4U', NULL, false, '2025-11-08T10:12:25.285473+00:00', '2025-11-10T12:19:13.081357+00:00', 'gf-superjolly', 'mekanikuri-asakidebeli-mosavlis-amghebi-jolly', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/361590ce-a6d5-4e3b-a024-0e4c8e33321d.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/d14cc809-5c30-4c74-b709-32eb6c8e9b7e.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('43043998-e354-4a09-b0a5-9a2593b4f1be', '6872f1fc-af75-4b10-98f7-821cc6a05a53', 'FLOW PACK MACHINES', 'პაკეტებში დაფასოება', '<ul><li>Suitable for powdery or granular products</li><li>Automatic dosing machine from 100 grams up to 1 kg</li><li>40L conical hopper. with product load approximately 1.80 meters from the ground</li><li>Productivity up to 8-10 pieces per minute</li></ul>', '<ul><li>შესაფერისი ფქვილის ან გრანულირებული პროდუქტებისთვის</li><li>ავტომატური დოზირების სასწორი 100 გრამიდან 1 კილოგრამამდე</li><li>40 ლიტრიანი კონუსური ხუფი, პროდუქტის დატვირთვის სიმაღლე მიწიდან დაახლოებით 1.80 მეტრი</li><li>წარმადობა — 8-10 ცალი წუთში</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/582b9148-630b-43a4-aa28-6c07aa8ac77c.webp', 'https://youtu.be/KNHGVHLamKA', NULL, false, '2025-11-05T16:39:10.292102+00:00', '2025-11-11T09:27:57.01054+00:00', 'flow-pack-machines', NULL, '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/f68c3da2-1a43-43ae-8ec5-b2fbbf513386.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('96f5a462-66f4-46b7-8e03-f659733a35c8', '254399a4-bf80-4fde-bbc7-35afc03d7bb4', 'FAMA pruning PRD ', 'Fama PRD-ხეხილის ბაღის სასხლავი  ', '<ul><li>Max height topping: 3.75 meters</li><li>MAX CUTTING HEIGHT : Horizontal 4,10 mt/ Vertical 6,20 mt</li><li>Flanging system to attach to tractor included</li><li>5 movement joystick</li><li>Extra hydraulic system at request</li></ul>', '<ul><li>თავაების გადაჭრის მაქსიმალური სიმაღლე: 3.75 მეტრი</li><li>ჭრის მაქსიმალური სიმაღლე:</li></ul><p>- ჰორიზონტალური: 4.10 მ</p><p>- ვერტიკალური: 6.20 მ</p><ul><li>ჩამრთველი სისტემა ტრაქტორზე დასამაგრებლად (ფლანჟირება) შემავალია</li><li>5-წერტილიანი ჯოისტიკით კონტროლი</li><li>დამატებითი ჰიდრავლიკური სისტემა (მოთხოვნის მიხედვით)</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/dee8c2f2-e2a6-42d8-9ea6-24c9e95ca288.webp', 'https://youtu.be/tweEIoi-asw', NULL, false, '2025-11-06T13:03:04.209251+00:00', '2025-11-11T07:37:14.786211+00:00', 'fama-pruning-prd', 'fama-gaskhvlis-aparati-prd-diskith', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
