INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('af2b51ac-0ab7-4b4b-900f-bdcd288e7d2f', NULL, 'L- shaped pruning machine', 'L-ფორმის ვენახის საკრეჭი', '<ul><li>L-shaped pruning machine to cut one row in one pass</li><li>Lateral movement: 35 cm</li><li>Inclination: 30°</li><li>Height regulation: 50 cm</li><li>Electric control from tractor with 5 movement joystick</li></ul><p><br></p>', '<ul><li>L-ფორმის კონსტრუქცია — ერთი მწკრივის გასხვლა ერთ გავლისას</li><li>გვერდითი გადაადგილება: 35 სმ</li><li>დახრის კუთხე: 30°</li><li>სიმაღლის რეგულირება: 50 სმ</li><li>ელექტრული მართვა კაბინიდან — 5-მოძრაობიანი ჯოისტიკით</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/8cb7963d-cd72-48f7-80db-e51e2af6f4d7.webp', 'https://youtu.be/K5ofmd0Oif4', NULL, false, '2025-11-09T20:27:07.655941+00:00', '2025-11-12T12:22:12.110487+00:00', 'l-shaped-pruning-machine', 'l-phormis-sakreji-mankana', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/b209c2b3-a1ab-413d-83dd-54c43d4d9aaf.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('07786f4a-6512-425f-af0a-36057487ffd1', NULL, 'Cold storages', 'სამაცივრე საწყობები', '<ul><li>Turn-key project for controlled atmosphere and refrigeration system</li><li>Suitable for apples, pears, peaches, dry fruits and blueberries</li><li>Installation, service and maintenance available in Georgia</li></ul>', '<ul><li>Turn-key პროექტები რეგულირებადი ატმოსფეროსა და გაცივების სისტემებისთვის</li><li>შესაფერისი ვაშლის, მსხლის, ატმის, კაკლოვნების და მოცვის შესანახად</li><li>მონტაჟი, სერვისი და ტექნიკური მომსახურება ხელმისაწვდომია საქართველოში</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/82dfecfb-f213-4884-828c-29efb0f7f922.webp', 'https://youtu.be/p4dvm4nmVj8', NULL, false, '2025-11-09T20:05:00.994314+00:00', '2025-11-11T07:36:42.618376+00:00', 'cold-storages', 'tsivi-shenakhvis-sistemebi', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/e28752fc-c163-45f3-b090-b7d36ff69839.webp"]', NULL, '<p>Different solutions for different needs:</p><ul><li>Traditional controlled atmosphere and Ultra Low Oxygen</li><li>Low Ethylene</li><li>Low Ethylene controlled atmosphere</li><li>Experimental Systems</li><li>Berry Fruits</li></ul>', '<p>გადაწყვეტილებები სხვადასხვა საჭიროებისთვის:</p><ul><li>ტრადიციული რეგულირებადი ატმოსფერო და ულტრა დაბალი ჟანგბადი (ULO)</li><li>დაბალი ეთილენის დონე</li><li>დაბალი ეთილენის რეგულირებადი ატმოსფერო</li><li>ექსპერიმენტული სისტემები</li><li>მოცვის და სხვა კენკროვნების საცავი გადაწყვეტილებები</li></ul>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('f442439e-1c06-4230-9185-f529e72612d6', '6872f1fc-af75-4b10-98f7-821cc6a05a53', 'POLY BAG PACKAGING MACHINES', 'პოლიეთილენის პარკებში შესაფუთი დანადგარები', '<ul><li>High-capacity machine for packaging: potatoes, onions, carrots and other products in individual polyethylene bags - Thermosealed or Twisted bags</li></ul>', '<ul><li>მაღალი წარმადობის დანადგარი კარტოფილის, ხახვის, სტაფილოსა და სხვა პროდუქტების პოლიეთილენის პარკებში შესაფუთად. - თერმოდაბეჭდილი ან მობრუნებული (Twisted) ტიპის ჩანთები</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/e3bc40e5-b1df-407f-9a37-38f941b94f1a.webp', 'https://player.vimeo.com/video/1092161735?h=de3caefe1d&byline=0&portrait=0&dnt=true#chapter=17868429', NULL, false, '2025-11-05T13:32:24.804302+00:00', '2025-11-11T09:29:58.507357+00:00', 'poly-bag-packaging-machines', 'poliethilenis-parkebshi-shesaphuthi-danadgarebi', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/8395c926-9921-4faf-a250-46711cf54073.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('84e82e58-684f-4252-933f-80780cc86edc', NULL, 'Pre-pruning equipment', 'ვენახის სასხლავი', '<ul><li>Light and practical, stable on sloping surfaces</li><li>Controlled by 5-outlet double-effect hydraulic distributor operating:</li><li>Side movement (40 cm)</li><li>Tilt movement (30°)</li><li>Height adjustment (80 cm)</li></ul><p><br></p>', '<ul><li>მსუბუქი და პრაქტიკული,( სტაბილური დახრილ ზედაპირებზე)</li><li>მართვა ხორციელდება 5-გამომყვანი, ორმაგი მოქმედების ჰიდრავლიკური დისტრიბუტორით, რომელიც უზრუნველყოფს:</li></ul><p>- გვერდით გადაადგილებას (40 სმ)</p><p>- დახრის მოძრაობას (30°)</p><p>- სიმაღლის რეგულირებას (80 სმ)</p>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/35f90806-6a5f-4fa3-a388-2972247c33bb.webp', 'https://www.facebook.com/watch/?v=402317042166116', NULL, false, '2025-11-10T10:17:00.282589+00:00', '2025-11-12T12:21:42.344046+00:00', 'pre-pruning-equipment', 'venakhis-sakrewi', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/c28393b1-cbef-46d8-a436-82d979266415.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/a7f1f595-788e-4e12-b052-ab7ebbff2928.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('617d6e25-30a8-4129-a7d2-7b04dbc216e4', NULL, 'Diva - Supra Ideal spryers for wineyards', 'Diva - Supra ვენახის საწამლი', '<ul><li>Available for 2 or 3 rows in one single pass</li><li>Low volume sprayers suitable for vineyard</li><li>Automatic washing system</li><li>Computer for control quantity of chemicals available as optional</li><li>Electrostatic system available on request</li></ul>', '<ul><li>ხელმისაწვდომია 2 ან 3 მწკრივის ერთდროულად შესაწამლად</li><li>მცირე მოცულობის საწამლები, იდეალურია ვენახისთვის</li><li>ავტომატური გამრეცხი სისტემა</li><li>ქიმიკატების დოზირების კონტროლის კომპიუტერი (მომართვის მიხედვით)</li><li>ელექტროსტატიკური სისტემა ხელმისაწვდომია მოთხოვნის შემთხვევაში</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/a5ff9616-07a9-4359-9437-9d1ca40c808e.webp', 'https://youtu.be/8IrvlAyssuI', NULL, false, '2025-11-11T10:35:27.552267+00:00', '2025-11-12T12:25:44.851585+00:00', 'diva-ideal-spryers-for-wineyards', 'diva-supra-venakhis-satsamli', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/30bf1744-ccc8-4c13-9355-013c28a6289e.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/80538c38-e57f-47d5-93fc-f546ca2948ec.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/8b6514bd-5df0-4b22-9313-6d338747e858.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/10e43fde-cb16-4b9f-b974-1023970eb0c6.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/498e9e76-aefd-42a9-8daa-397c45d18e6b.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('32f88dfd-e966-4f56-bb77-83ecae782839', '6872f1fc-af75-4b10-98f7-821cc6a05a53', 'NET BAG PACKAGING ', 'ბადეში შეფუთვა', '<ul><li>Suitable for oranges, potatoes, onions, avocado</li><li>Productivity up to 24 packs per minute</li><li>To be installed together with a multihead weighing machine</li><li>The packaging material can be customised based on customer requests</li></ul>', '<ul><li>შესაფერისია ფორთოხლის, კარტოფილის, ხახვისა და ავოკადოსთვის</li><li>წარმადობა — 24 შეფუთვამდე წუთში</li><li>ინსტალაცია ხდება მრავალთავიან სასწორ დანადგართან ერთად</li><li>შეფუთვის მასალა შესაძლებელია შეირჩეს დამკვეთის მოთხოვნების შესაბამისად</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/78309e5e-7923-4076-80cd-60ee359a4364.webp', 'https://player.vimeo.com/video/1092167310?h=de3caefe1d&byline=0&portrait=0&dnt=true#chapter=17899409', NULL, false, '2025-11-05T16:01:30.247319+00:00', '2025-11-11T09:29:31.798511+00:00', 'net-bag-packaging', 'badeshi-shephuthva', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/d075cb92-80f5-43b7-8346-5041e344e5d5.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('8b0e702f-ca47-4d39-91f2-4d64d10649a0', 'c19629da-f41c-4ffd-b835-3cf06a643579', 'Ideal spryer evolution mounted', 'Ideal  evolution - ასაკიდებელი შესაწამლი აგრეგატი', '<ul><li>Axial fan with an aluminum propeller</li><li>Hot galvanized frame</li><li>Polyethylene tank in various capacities (e.g., 400L to 1000L for mounted, or up to 3000L for trailed)</li><li>Gearbox with 2 speeds plus a neutral position</li><li>Equipped with double anti-drip brass jets</li></ul>', '<p>ვენტილატორი ალუმინის პროპელერით</p><p>ცხლად გალვანიზებული ჩარჩო</p><p>პოლითილენის ავზი სხვადასხვა ტევადობით (400 ლ-დან 1000 ლ-მდე ასაკიდებელი ვერსიისთვის, ან 3000 ლ-მდე მისაბმელისთვის)</p><p>გადაცემათა კოლოფი 2 სიჩქარით და ნეიტრალური მდგომარეობით</p><p>ორმაგი ანტი-წვეთოვანი ნიკელის ბუნიკებით</p>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/15d4a237-b314-4cd5-b840-23561a6b7cbd.webp', 'https://youtu.be/8P7e_e5UO4U', NULL, false, '2025-11-06T10:55:31.128697+00:00', '2025-11-12T12:24:11.6672+00:00', 'ideal-spryer-evolution-trailed', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('49eeb11d-ab68-4feb-8f39-8b11577cb058', '922727df-6a6a-43d2-b5b8-7a29c752214e', 'Manure spreader', 'Annovi-ს სასუქის შემტანი', '<ul><li>Small dimension: Perfect for orchard and vineyard </li><li>Mechanical chain conveyor with 3 speeds</li><li>Load capacity: 2,8 m3</li><li>Spread length 1-5 meters</li><li>Max height: 1,6 meters</li><li>Max width: 1.6 meters</li><li>Max length: 4,6 meters</li></ul>', '<ul><li>მცირე გაბარიტები — იდეალურია ბაღებისთვისა და ვენახებისთვის</li><li>მექანიკური ჯაჭვური ტრანსპორტიორი 3 სიჩქარით</li><li>ტვირთამწეობა: 2.8 მ³</li><li>გაფრქვევის სიგრძე: 1-დან 5 მეტრამდე</li><li>მაქსიმალური სიმაღლე: 1.6 მ</li><li>მაქსიმალური სიგანე: 1.6 მ</li><li>﻿მაქსიმალური სიგრძე: 4.6 მ</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/c9025f88-40e1-4f37-9c3c-0f6aa40b9106.webp', 'https://youtu.be/auNHlj-PrLw', NULL, false, '2025-11-06T09:20:22.457918+00:00', '2025-11-10T12:13:15.760218+00:00', 'manure-spreader', 'annovi-s-sasukis-gamphrkvevi-satqortsni', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('5650719c-45a9-4f5f-b60c-873fea582676', NULL, 'Harvesting system yellow devil', 'მოსავლის აღების სისტემა Yellow Devil', '<ul><li>Suitable for big plantations of almonds and walnuts</li><li>4-wheel drive vibrating unit, fully hydrostatic with built-in conveyor panel</li><li>4-wheel drive receiving unit with hydraulic movable bulkhead, conveyor belt, elevator, leaf remover and bins holder.</li><li>Possibility to integrate hulling processing for almonds</li></ul>', '<ul><li>ნუშისა და კაკლის დიდი პლანტაციებისთვის</li><li>4-ბორბლიანი ვიბრირებადი ერთეული, სრულიად ჰიდროსტატიკური, ინტეგრირებული კონვეიერის პანელით</li><li>4-ბორბლიანი მიღების ერთეული ჰიდრავლიკური მოძრავი გადაკეტვით, კონვეიერის ლენტი, ლიფტი, ფოთლების გამწმენდი და ყუთების საყრდენით</li><li>ოფციურია -ნუშის წენგოს სარჩევი</li></ul><p><br></p>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/5b6b1d77-5397-462c-81ab-197107637d6f.webp', 'https://youtu.be/Hij1G9mX-gU', NULL, false, '2025-11-07T14:10:09.753982+00:00', '2025-11-07T14:10:09.753982+00:00', 'harvesting-system-yellow-devil', 'mosavlis-aghebis-sistema-yellow-devil', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/d2ef948f-4d88-4dcc-b7c9-9c417d9f5fc0.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/5c115a79-2a5f-41bf-883f-cc705610a984.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/e910dcc3-1260-47c4-bf18-ef1d77e48403.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('1618db40-a9e1-472f-a175-f312bb8ea32a', 'c19629da-f41c-4ffd-b835-3cf06a643579', 'Ideal spryer perfection', 'Ideal  perfection -შესაწამლი აპარატი', '<ul><li>Fan with two counter-rotating propellers (double helix)</li><li>Produces a high and perfectly balanced air volume, distributed symmetrically on both sides</li><li>Double anti-drip brass jets</li><li>Polyethylene tank. Trailed versions are available with tank capacities from <strong>800 to 3,000 liters</strong></li><li>Circuit rinsing device</li></ul>', '<p>ვენტილატორი ორი ერთმანეთის საწინააღმდეგოდ მბრუნავი პროპელერით ქმნის მაღალ და სრულად დაბალანსებულ ჰაერის ნაკადს, რომელიც სიმეტრიულად ნაწილდება ორივე მხარეს</p><p> ორმაგი ანტი-წვეთოვანი ნიკელის ბუნიკები</p><p> პოლითილენის ავზი — მისაბმელი ვერსიები ხელმისაწვდომია 800-დან 3000 ლიტრამდე ტევადობით</p><p> სისტემის გამომრეცხი მოწყობილობით.</p>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/b40b7f0c-43e6-43a6-8b50-f1237ad1d514.webp', 'https://youtu.be/fL7JwmGTvcA', NULL, false, '2025-11-06T10:36:23.343786+00:00', '2025-11-11T09:13:06.415244+00:00', 'ideal-spryer-perfection', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('25809594-5cfe-4adb-8802-0e238fe3ac3a', NULL, 'Handshakers Cifarelli', ' შეიკერი', '<ul><li>Handshaker suitable for almonds, hazelnuts, olives and other fruits</li><li>Light structure only 14 kg</li><li>Powerful 52 cc displacement made in italy</li><li>More than 2000 vibrations per minute</li><li>Hold hook 42 mm</li></ul>', '<ul><li>ხელით შოკერი შესაფერისია ნუშის, თხილის და ზეთისხილისთვის&nbsp;</li><li>მსუბუქი კონსტრუქცია — 14 კგ</li><li>ძლიერი ძრავი, მოცულობა 52 ც.სმ, წარმოებული იტალიაში</li><li>2000-მდე როტაცია წუთში</li><li>დამჭერი ღერძი- 42 მმ</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/ea409d9d-db5f-472f-914a-031072eac8c3.webp', 'https://youtu.be/sdYE7UZHJ9k', NULL, false, '2025-11-07T14:20:59.823495+00:00', '2025-11-11T12:56:14.763224+00:00', 'handshakers-cifarelli', 'sheikeri-cifarelli', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/ded71943-fa33-43f6-9c9c-5d8d64672b04.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('ba0be5af-aa2a-4fe7-9725-dde9641422ec', NULL, 'Fama bilateral pruning machine', 'ორმხრივი საკრეჭი ', '<ul><li>Possibility to prune 2 rows in one pass</li><li>Minimum opening: 1,10 mt</li><li>Maximum opening: 1,80 mt</li><li>Height regulation: 50 cm</li><li>Topping and vertical cutting in one pass</li><li>Extra hydraulic system available on request</li><li>Electric control from tractor with 5 movement joystick</li></ul><p><br></p>', '<ul><li>შესაძლებელია ორი მწკრივის ერთდროული გასხვლა ერთ გავლისას</li><li>მინიმალური გაშლა: 1.10 მ</li><li>მაქსიმალური გაშლა: 1.80 მ</li><li>სიმაღლის რეგულირება: 50 სმ</li><li>თავაკუწვა და ვერტიკალური ჭრა ერთ გავლისას</li><li>დამატებითი ჰიდრავლიკური სისტემა ხელმისაწვდომია მოთხოვნის შემთხვევაში</li><li>ელექტრული მართვა ტრაქტორიდან 5-მოძრაობიანი ჯოისტიკით</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/b0dcf0d5-4ee1-447b-912c-dab6a7ab7a53.webp', 'https://www.facebook.com/watch/?v=1030827115690292', NULL, false, '2025-11-09T20:15:24.022895+00:00', '2025-11-20T11:23:44.633294+00:00', 'fama-bilateral-pruning-machine', 'ormkhrivi-gaskhvlis-mankana', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/1e5038b8-fbc8-4d40-930a-b00e35a166fc.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/f7f82632-44f0-4449-aa4a-92aa678b9933.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/96e5afdb-8fd9-4f0e-b9be-28a0beaa6edb.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('0cd0658b-0840-490c-96f6-2b6322682159', '254399a4-bf80-4fde-bbc7-35afc03d7bb4', 'Fama pruning CKD', 'Fama CKD-ხეხილის ბაღის სასხლავი (სეგმენტური)', '<ul><li>Available with disk and mowing bar</li><li>Horizontal cut and topping in one single pass</li><li>Side movement:50 cm</li><li>Inclination of the cutting header: 30°</li><li>Height adjustment of cutting blades</li></ul>', '<ul><li>ხელმისაწვდომია როგორც დისკური, ასევე სეგმენტური მჭრელი დანებით</li><li>ვერტიკალური და ჰორიზონტალური ჭრა&nbsp;</li><li>გვერდითი გადაადგილება: 50 სმ</li><li>ჭრის მექანიზმის დახრის კუთხე: 30°</li><li>ჭრის&nbsp;სიმაღლის რეგულირება</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/bf4b019b-5391-456c-b804-5e0c25c3edc1.webp', 'https://www.youtube.com/shorts/ld400aP8WAA?feature=share', NULL, false, '2025-11-06T12:54:20.254856+00:00', '2025-11-10T12:17:44.913699+00:00', 'fama-pruning-ckd', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('7de8ad6f-43f2-40a7-99ee-524220ad5925', '9c4776ab-9235-4817-84b0-7ab17c478cc3', 'Mulcher for stones and grass', 'ქვის სამტვრევი', '<ul><li>Heavy mulcher for grass, stones and prunings</li><li>Available from 140 to 220 cm</li><li>Manual side shift</li><li>Possibility to install lateral disk</li></ul>', '<p>მძიმე მულჩერი ბალახისთვის, ქვებისთვის და ტოტებისთვის</p><p>ხელმისაწვდომია 140-დან 220 სმ-მდე</p><p>მექანიკური გვერდითი გაწევით</p><p>შესაძლებელია გვერდითი დისკის დაყენება</p>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/25330701-2311-4955-905c-aa7b1f9999e2.webp', 'https://youtu.be/YR_DiBGaI_I', NULL, false, '2025-11-06T17:02:54.886269+00:00', '2025-11-12T12:28:53.675335+00:00', 'stonemulcher', NULL, '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/0520fb5a-bb69-4681-97ba-40472986b431.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/dec4279d-0263-4ac5-a0e0-b18047ce79fa.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('c4d465f1-71c2-4223-9ae8-fa3a0597ff9d', '6872f1fc-af75-4b10-98f7-821cc6a05a53', 'CARDBOARD PUNNETS', 'მუყაოს ყუთი', '<ul><li>Machine suitable for apples, pears and other stone fruits</li><li>Semi-automatic machine for 4 or 6 packs</li><li>Automatic closing of the cardboard pack</li><li>Available in different formats and productivity</li></ul>', '<ul><li>მანქანა შესაფერისია ვაშლის, მსხლისა და სხვა ხეხილისთვის</li><li>ნახევრად ავტომატური დანდგარი 4 ან 6-აინ შეფუთვაზე</li><li>მუყაოს პაკეტის ავტომატური დახურვა</li><li>ხელმისაწვდომია სხვადასხვა ფორმატსა და წარმადობაზე</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/04c7192a-9fd7-448a-a845-1108ca3b2cf6.webp', 'https://player.vimeo.com/video/841249278?h=de3caefe1d&byline=0&portrait=0&dnt=true', NULL, false, '2025-11-05T16:30:50.126082+00:00', '2025-11-11T12:53:42.656102+00:00', 'cardboard-punnets', 'muqaos-quthi', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('2534d5e6-fc97-464e-bba6-8a280c71646d', '9c4776ab-9235-4817-84b0-7ab17c478cc3', 'Forestry mulcher with hammer roller', 'სატყეო მულჩერი ', '<ul><li>Available in different sizes: from 2.1 to 2.5 meters</li><li>Forestry rotor with swinging hammers</li><li>Double-drive forestry mulcher</li><li>Equipped with hydraulic push frame</li></ul>', '<ul><li>ხელმისაწვდომია სხვადასხვა ზომით: 2.1-დან 2.5 მეტრამდე სამუშაო სიგანით</li><li>როტორი მოძრავი ჩაქუჩებით</li><li>ორმაგი ძრავით (გადაბმულობით)&nbsp;</li><li>აღჭურვილია ჰიდრავლიკური ჩამწევი/დამჭერი ჩარჩოთი</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/b59aecc8-0514-48af-8af1-6bfb96933bba.webp', 'https://youtu.be/_1Er99YyMYo', NULL, false, '2025-11-05T18:01:12.089454+00:00', '2025-11-12T12:11:39.081651+00:00', 'forestry-mulcher-with-hammer-roller', 'tqis-mulcheri-chakuchiani-valikith', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/44c89f19-e9c0-4d39-a401-950841bb3e55.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('8e22c766-7c6a-4177-9de4-f417a5550e45', NULL, 'Trailed shaker tornado umbrella', 'ასაკიდებელი აგრეგატი Tornado', '<ul><li>Powerful tractor mounted shaker for medium-big plantation</li><li>Suitable for almond and walnuts</li><li>Telescopic 180 rotation to work 2 rows in one single pass</li><li>Operating pressure 350 bars with independent hydraulic system</li><li>Joystick to control machine movements</li><li>Only 2 operators needed for harvesting</li><li>Available with and without umbrella</li></ul>', '<ul><li>ძლიერი ტრაქტორზე დამაგრებული აგრეგატი საშუალო და დიდი პლანტაციებისთვის</li><li>ნუშისა და კაკლის ბაღებისთვის</li><li>ტელესკოპური 180 გრადუსიანი ბრუნვა, რომელიც საშუალებას იძლევა 2 მწკრივზე ერთდროულად მუშაობის</li><li>სამუშაო წნევა: 350 ბარი, დამოუკიდებელი ჰიდრავლიკური სისტემით</li><li>ჯოისტიკი აგრეგატის მოძრაობებისტვის</li><li>მოსავლის აღებისთვის საჭიროა მხოლოდ 2 ოპერატორი</li><li>ხელმისაწვდომია ქოლგით და უქოლგო ვერსიით</li></ul><p><br></p>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/791e9f95-c08f-4854-a8e9-93b6e36d9621.webp', 'https://youtu.be/uNFnT-RQeLU', NULL, false, '2025-11-07T13:58:05.407994+00:00', '2025-11-07T13:59:20.619613+00:00', 'trailed-shaker-tornado-umbrella', 'asakidebeli-agregati-tornado', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/815757ac-065c-44e6-9951-9a70b46a5134.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('b47fa3e4-c996-4c4c-8cf3-e450ae0eb950', NULL, 'Trailed shaker petska', 'საკიდებელი შეიკერი Petska', '<ul><li>Suitable for almonds, plumbs and other stone fruits</li><li>Tractor mounted shaker developed for small medium plantations</li><li>Hydraulic control of vibration and clamping from the tractor cabin</li><li>Thanks to the turn of 180 degrees is possible to work 2 rows in one pass</li><li>Capable to shake up to 1 tree/minute</li></ul>', '<ul><li>გამოიყენება სხვადახსვა ხეხილის ბაღებისთვის</li><li>ტრაქტორზე დამაგრებული აგრეგატი, განკუთვნილი მცირე და საშუალო პლანტაციებისთვის</li><li>ჰიდრავლიკური ვიბრაციის და დაჭერის კონტროლი ტრაქტორის კაბინიდან</li><li>180 გრადუსიანი ბრუნვის წყალობით შესაძლებელია მუშაობა 2 მწკრივზე ერთდროულად</li><li>შესაძლებელია 1 ხის&nbsp;დაკრეფა წუთში</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/a004c948-4828-4c3c-aac1-212cd6b649af.webp', 'https://youtu.be/5HuZuBIvInY', NULL, false, '2025-11-07T14:15:27.185968+00:00', '2025-11-11T07:33:19.764465+00:00', 'trailed-shaker-petska', 'sakidebeli-sheikeri-petska', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/99d0d9f1-bb0c-49ef-b1be-423690fd0bf6.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/2004309a-cd4e-45be-a882-d6582c876671.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/d7a9ea71-f739-4863-a085-e70d7970acf1.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('ae052c15-2191-4308-8807-939086c5d8e4', 'de81945e-2e83-4767-a29d-0d76ce131659', 'trailed harvesting platform', 'მოსავლის ასაღები პლატფორმა', '<ul><li>Platform length 4 metres with minimum height of 90 cm and&nbsp;maximum height of 295 cm&nbsp;&nbsp;</li><li>Equipped with side balconies that can be opened hydraulically by 80 cm on&nbsp;each side with controls on the front of&nbsp;the platform&nbsp;&nbsp;</li><li>Roller conveyors with capacity of 5 bins&nbsp;&nbsp;</li><li>Load capacity 1600 kg&nbsp;&nbsp;</li><li>Oversized tyres for greater stability&nbsp;</li></ul>', '<p>პლატფორმის სიგრძე — 4 მეტრი, მინიმალური სიმაღლე 90 სმ, მაქსიმალური სიმაღლე 295 სმ</p><p> მოწყობილია ჰიდრავლიკურად გახსნადი გვერდითი სადგომებით — თითოეულ მხარეს 80 სმ-მდე.</p><p> მართვის პანელით პლატფორმის წინა ნაწილში</p><p> როლიკიანი ტრანსპორტიორი 5 ყუთის ტევადობით</p><p> ტვირთამწეობა — 1600 კგ</p><p> გადიდებული საბურავები უკეთესი სტაბილურობისთვის</p>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/6e113a56-bda9-40ff-95e9-4d27a88cb892.webp', 'https://youtu.be/QmQ94hWfoiI', NULL, false, '2025-11-06T14:19:44.867753+00:00', '2025-11-11T09:17:16.367198+00:00', 'trailed-harvesting-platform', NULL, '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/eb2387b5-075d-4c89-b58d-51edce03472c.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('0f0125f2-395f-4eff-9e72-c7554aa7bdc3', NULL, 'Facma Trailed harvester', 'ასაკიდებელი მოსავლის ამღები ტექნიკა', '<ul><li>Trailed harvester suitable for tractors with minimum 30 HP</li><li>Tubes for harvesting also in difficult land conditions</li><li>Hulling and cleaning system for “anakliuri” variety</li><li>Up to 500 kg/hour harvesting capacity</li><li>Lateral brush available as optional</li></ul>', '<ul><li>ასაკიდებელი მოსავალი ამღები ტექნიკა, საჭიროებს მინიმუმ 30 ცხენის ძალის მქონე ტრაქტორს.</li><li>მილები მოსავლის აღებისთვის რთულ რელიეფზეც</li><li>„ანაკლიური“ ჯიშის დასუფთავების სისტემა</li><li>წარმადობა: 500 კგ საათში</li><li>გვერდითი შემკრები (დამატებით ოფციის შემთხვევაში)</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/c7e86355-a7e2-4ed6-9ff5-e3a8e4a5b86e.webp', 'https://youtu.be/rcPtWOq8W8g', NULL, false, '2025-11-08T09:56:07.317693+00:00', '2025-11-11T12:55:44.444086+00:00', 'facma-trailed-harvester', 'asakidebeli-mosavlis-amghebi-agregati', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/d5957139-0296-4ab4-b552-d3c662f3facd.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('0ae06bb2-7df7-4874-9f1d-be0be47ecb4a', 'de81945e-2e83-4767-a29d-0d76ce131659', 'Selfpropelled harvesting platforms', 'მოსავლის ამღები პლატფორმები', '<ul><li>Fruit drop into the bins is performed through a rotating disk</li><li>Carpet with waves with different speed to avoid collision of the fruits</li><li>Rotating brush on the filler</li><li>Automatic bin saturation stop as well as automatic repositioning delivery on new empty bin</li><li>Wide and comfortable working area on the sides of upper conveyors</li></ul>', '<ul><li>მაბრუნი შნეკის მეშვეობით ხილი თასებში თავსდება</li><li>შემტანი ჯამები სხვადასხვა სიჩქარით, რათა არ მოხდეს ხილის დაბეჟვა</li><li>დამატებითი მბრუნავი ჯაგრისი დატვირთვის ადგილას.</li><li>ყუთის ავტომატური გამოცვლა ავსების მომენტში.</li><li>ფართო და კომფორტული სამუშაო ზონა ზედა კონვეიერების გვერდებზე</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/3eddd040-0d7f-4cab-a01a-89ae892a9f5e.webp', 'https://youtu.be/vSSZW1Zh60s', NULL, false, '2025-11-06T13:20:34.218429+00:00', '2025-11-11T09:21:01.8081+00:00', 'selfpropelled-harvesting-platforms', 'mosavlis-amghebi-platphormebi', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/d297d49a-8db5-4859-8ba7-23b9ccfb7329.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('39f907fb-3de5-4e29-ae1f-85fe9ba83e58', NULL, 'Hulling machine estupina', 'Estupina ნუშის წენგოს სარჩევი დანადგარი', '<ul><li>Machine for remove the almond green peel</li><li>Available capacity from 500 kg to 6 tons/hour</li><li>Suitable for both hard shell and softshell varieties</li><li>Possibility to regulate the machine depending on variety (guara, penta, makako, supernova, avijor..)</li></ul>', '<ul><li> ნუშის მწვანე ქერქის(წენგოს) მოსაშორებლად</li><li>ხელმისაწვდომი წარმადობა: 500 კგ-დან 6 ტონამდე საათში</li><li>გამოსადეგია როგორც მყარი, ისე რბილი ქერქის ჯიშებისთვის</li><li>შესაძლებლია დანადგარის რეგულირებისა ჯიშის მიხედვით (გუარა, პენტა, მაკაკო, სუპერნოვა, ავიხორი და სხვა)</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/ca3ca46f-5a34-488d-b6f8-8f3fdfcd823f.webp', 'https://www.facebook.com/watch/?v=842090773348148', NULL, false, '2025-11-08T10:33:43.314743+00:00', '2025-11-12T12:32:14.11164+00:00', 'hulling-machine-estupina', 'nushis-tsengos-sarchevi-danadgari-estupina', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/7c81b5e6-bc11-43ba-aad2-77336b90a124.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/20d9166d-8b10-452f-800e-9f1ac7519db8.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('55a997da-247a-409d-96b1-752cb426b359', NULL, 'Cleaning line and drying equipment', 'საწმენდი და საშრობი ხაზი', '<ul><li>Turn-key solutions for cleaning,hulling and drying of almonds, huzelnuts and walnuts</li><li>Tailor made projects on customer requests</li><li>Stone removing system with water tanks</li><li>Leaves and branches remover</li><li>Dryers available from 5 to 12 tons capacity</li><li>Manual selection tables for perfect results</li></ul>', '<ul><li>სრული გადამუშავების ხაზი ნუშის, თხილის და კაკლის გასაწმენდად და გასაშრობად</li><li>პროექტები მზადდება მომხმარებლის მოთხოვნების მიხედვით</li><li>ქვის გამცლელი სისტემა წყლის ავზებით</li><li>ფოთლების და ტოტების გამწმენდი</li><li>საშრობები&nbsp;ხელმისაწვდომია 2-დან 12 ტონამდე სიმძლავრით</li><li>მექანიკური გადარჩევის მაგიდები იდეალური შედეგებისთვის</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/e6043482-6f4b-4c40-9e2b-b9521a6dd495.webp', 'https://youtu.be/tvfScKF7aOs', NULL, false, '2025-11-08T10:43:28.096133+00:00', '2025-11-11T09:32:27.139741+00:00', 'cleaning-line-and-drying-equipment', 'satsmendi-da-sashrobi-khazi', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/cc0b7cba-c247-4d84-bcbb-a4220d48c609.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/e57d9595-318d-48df-b0f7-02fccbbeb218.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('6ba338b3-34e6-4af2-a85b-fff80d5b8270', NULL, 'Cracking machines for almonds and huzelnuts', 'ნუშისა და თხილის სატეხი ქარხანა.', '<ul><li>Cracking machine for almonds available from 500 kg to 2 tons capacity per hour</li><li>Suitable for different almonds varieties (guara, supernova, penta, avijor, makako…)</li><li>Very low damage percentage of the kernels (less than 4%)</li><li>No need for calibration before the cracking for almonds</li><li>Separation of the kernels from the shell thanks to vibration and air&nbsp;</li><li>Up tp 5 caliber of kernel after cracking thanks to automatic calibration system</li></ul>', '<ul><li>ნუშის სატეხი ქარხანა, ხელმისაწვდომი სიმძლავრით 500 კგ-დან 2 ტონამდე საათში</li><li>შესაფერისი სხვადასხვა ნუშის ჯიშებისთვის (გუარა, სუპერნოვა, პენტა, ავიხორი, მაკაკო და სხვ.)</li><li>გულის დაზიანების დაბალი პროცენტი (4%-ზე ნაკლები)</li><li>ნუში დამტვრევამდე არ საჭიროებს კალიბრაციას</li><li>ნაჭუჭი გამოყოფა გულიდან ვიბრაციის და ჰაერის საშუალებით</li><li>ავტომატური კალიბრაციის სისტემის წყალობით დამტვრევის შემდეგ შესაძლებელია ნუშის 5 კალიბრად დახარისხება.</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/0734c7ec-fce9-4fa2-b312-138c56d074b5.webp', 'https://youtu.be/Ri1M-zfv3Qs', NULL, false, '2025-11-08T10:51:44.008114+00:00', '2025-11-11T09:31:40.021634+00:00', 'cracking-machines-for-almonds-huzelnuts', 'nushisa-da-thkhilis-satekhi-karkhana', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/76957641-6036-49b0-8830-8d75d474ccea.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/021472b3-031f-4532-b8fc-9665f820af24.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/a1bec6fe-6e2d-4bba-8a91-a27b3db645d9.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('ba0cbcee-e954-44ee-9cc2-e61a46e52b38', '4635055a-9c0c-48ae-8544-f585a5a38e3b', ' Calibration and sorting', 'ხილის კალიბრაციისა და დახარისხების დანადგარები', '<ul><li>Turn-key solution for fruit calibration and sorting</li><li>Possibility to calibrate and sort: Apples, pears, apricots, flat peaches, plums, avocados, citrus, pomegranates, tomatoes, onions, and potatoes.</li><li>Capacity: from 2 to 15-20 tons per hour</li><li>Sorting by: Weight, diameter, color, and external quality.</li><li>Service and spere parts available in Georgia</li></ul>', '<ul><li>სრულად აღჭურვილი (Turn-key) სისტემები ხილის კალიბრაციისა და დახარისხებისთვის</li><li>შესაძლებელია შემდეგი კულტურების კალიბრაცია და დახარისხება: ვაშლი, მსხალი, გარგარი, ბრტყელი ატამი, ქლიავი, ავოკადო, ციტრუსი, ბროწეული, პომიდორი, ხახვი და კარტოფილი</li><li>წარმადობა: 2-დან 15-20 ტონამდე საათში</li><li>დახარისხების კრიტერიუმები: წონა, დიამეტრი, ფერი და გარე ხარისხი</li><li>სერვისი და სათადარიგო ნაწილები ხელმისაწვდომია საქართველოში</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/a8880c1d-4cc0-4c4f-a937-9642381c5da4.webp', 'https://youtu.be/yPUnTLVwN64', NULL, false, '2025-11-07T09:53:23.404698+00:00', '2025-11-11T12:53:21.655819+00:00', 'calibration-and-sorting', 'khilis-kalibratsiisa-da-dakhariskhebis-danadgarebi', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/ff0c3d91-0f7b-4807-974a-67a82c267fe3.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/ee338a89-134d-44c1-87bf-df0a7d664115.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/7cfb62b3-6ba8-4280-9306-04f48bbeb953.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/9f72a82c-5c3b-4610-807d-a742a8abecf7.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/8bf12449-f6a4-4455-85fa-e558c7522026.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('e1a3a481-c1d6-43f2-a223-9052f7551296', '6872f1fc-af75-4b10-98f7-821cc6a05a53', 'PUNNETS PACKAGING', 'კონტეინერში შეფუთვა', '<ul><li>The machine is suitable to handle 0,5 to 1 kg punnets</li><li>Suitable for cherry tomatoes, blueberries, cherries, cucumbers and other fruits</li><li>Complete with electrical control cabinet to control the automatic functions</li></ul><p><br></p>', '<ul><li>დანადგარი შესაფერისია 0.5-დან 1 კგ-მდე შეფუთვებისათვის</li><li>შესაფერისია ალუბლის, მოცვის, ჩირის, კომბოსტოსა და სხვა ხილისთვის</li><li>აღჭურვილია ელექტრო მართვის კაბინეტით ავტომატური ფუნქციების კონტროლისატვის.</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/5d500210-3c38-40dd-b4ba-cc928817028d.webp', 'https://player.vimeo.com/video/1092163460?h=de3caefe1d&byline=0&portrait=0&dnt=true#chapter=17867695', NULL, false, '2025-11-05T16:18:57.697689+00:00', '2025-11-11T09:29:14.605231+00:00', 'punnets-packaging', 'konteinershi-shephuthva', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/fc01124c-36d8-4f82-896d-46ec8cb0cd51.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('0b17217b-82e5-4a71-9370-5c6d5a683fdc', NULL, 'Ideal Spryers for vineyards drop-save', 'Ideal ვენახის საწამლი Drop-Save', '<ul><li>Can spray 2 complete rows recovering on average 50% of liquid sprayed</li><li>Hydraulic central lifting and arms’ extension</li><li>High pressure brass pump and non-return valve on circuit rinsing device</li><li>Tank-washing device as standard</li></ul>', '<ul><li>შესაძლებელია 2 სრულყოფილი მწკრივის შესაწამლად, საშუალოდ 50%-ით პრეპარატის დაბრუნებით</li><li>ჰიდრავლიკური ცენტრალური აწევა და მკლავების გახსნა</li><li>მაღალი წნევის სპილენძის ტუმბო და გამსვლელი სენსორი ხაზის გასასუფთავებელი მოწყობილობით</li><li>მოცულობის საცავის გამოსარეცხი მოწყობილობა სტანდარტულად</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/66a0f50e-abba-49cd-8fe8-091ca8f08c6f.webp', 'https://youtu.be/6fSwpP8gZmM', NULL, false, '2025-11-11T10:49:25.760145+00:00', '2025-11-11T10:51:29.064349+00:00', 'ideal-spryers-for-vineyards-drop', 'ideal-venakhis-satsamli-drop-save', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/7d49a86c-b57d-49a7-b99d-9afb5bcccd8f.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/14581d97-8126-4518-960e-02f8bce29bb9.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/f6c635b9-1134-4b70-a15f-ecb343eec0c0.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('0880a86b-1028-4e32-a69b-3cf73b37e788', '9c4776ab-9235-4817-84b0-7ab17c478cc3', 'Mulcher TCK for prunings', 'TCK  მულჩერი ნასხალავის დასაქუცმაცებლად.', '<ul><li>Available in different sizes: from 1.0 to 2.1 meters</li><li>Pick-up roll for prunings</li><li>Can cut pruning up to 6 cm</li><li>Discharge grill with calibrated holes</li><li>Rotor with helical cutting system</li></ul>', '<ul><li>ხელმისაწვდომია სხვადასხვა სამუშაო სიგანით: 1.0-დან 2.1 მეტრამდე</li><li>ნასხლავის ასაღები საკრეფი ვალიკი</li><li>შესაძლებელია ტოტების დაქუცმაცება მაქსიმუმ 6 სმ დიამეტრამდე</li><li>გამოტანის სისტემა კალიბრირებული ხვრელების მქონე გისოსით</li><li>დაქუცმაცების როტორი სპირალური (ჰელიკური) ჭრის სისტემით</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/687f8319-f4ba-43a7-9543-a12ef999d440.webp', 'https://youtu.be/Fct58NKrs9w', NULL, false, '2025-11-05T17:45:41.292791+00:00', '2025-11-12T12:11:59.119975+00:00', 'mulcher-tck-for-prunings', 'tck-mulcheri-naskhalavis-dasakutsmatseblad', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('bab82a0d-e607-49b3-842c-96e140453152', '254399a4-bf80-4fde-bbc7-35afc03d7bb4', 'Fama pruning intensive orchard', 'სასხლავი ინტენსიური ბაღებისთვის', '<ul><li>Pruning machine for superintensive orchards</li><li>Vertical mowing bar of 2.10/2.50/3.00 mt</li><li>Height adjustment of cutting blades 50 cm</li><li>Side movement 50 cm</li></ul>', '<p>სუპერინტენსიური ბაღებისთვის სასხლავი მანქანა</p><p> ვერტიკალური მჭრელი  – 2.10 / 2.50 / 3.00 მ</p><p> სიმაღლის რეგულირება – 50 სმ</p><p> გვერდითი გადაადგილება – 50 სმ</p>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/a3e3d99c-39fa-4f26-bcba-d5371abebe19.webp', 'https://youtu.be/HIB7E6w2hJY', NULL, false, '2025-11-06T14:05:18.666974+00:00', '2025-11-12T12:15:24.76172+00:00', 'fama-pruning-intensive-orchard', 'sasxlavi-intensiuri-bagebistvis', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/3aa8ca76-826b-4157-9608-6cd73c46dc51.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('4f74abaa-9607-4ffb-9afe-9523db45dfe7', '922727df-6a6a-43d2-b5b8-7a29c752214e', 'Leaves stripper', 'ვენახის საბურველი,ფოთლების გამცლელი', '<ul><li>Operating pressure: 0.5 to max. 0.7bar;</li><li>Working area: from 40 cm to 70cm</li><li>Working speed: 1.5 – 4 km/h</li><li>Medium compressor 600 Lt/min 45 HP min (DF700)</li><li>Large compressor 1400 Lt/min 75/80 HP min (DFB</li></ul>', '<ul><li>მუშაობის წნევა: 0.5 დან მაქსიმუმ 0.7 ბარამდე</li><li>მუშაობის ფართობი: 40 სმ-დან 70 სმ-მდე</li><li>მუშაობის სიჩქარე: 1.5 – 4 კმ/სთ</li><li>საშუალო კომპრესორი: 600 ლ/წთ, მინიმუმ 45 ცხ.ძ. (DF700)</li><li>დიდი კომპრესორი: 1400 ლ/წთ, მინიმუმ 75/80 ცხ.ძ. (DFB)</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/d8715853-6e9c-4b8b-bcea-c0caf2c42379.webp', 'https://youtu.be/2-IYwW_qJVM', NULL, false, '2025-11-06T09:58:13.401569+00:00', '2025-11-11T07:27:49.173417+00:00', 'leaves-stripper', 'phothlebis-gamtsleli-aparati', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/506748c8-8976-44f5-b554-755f6037c16b.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('8c85336e-4bfd-400e-8829-aaf56596ff19', NULL, 'U-shaped pruning machine fama', 'U-ფორმის ვენახის საკრეჭი', '<ul><li>U-shaped pruning machine with automatic centering system</li><li>Minimum opening: 40 cm</li><li>Maximum opening: 110 cm</li><li>Height regulation: 102 cm</li><li>Electric control from tractor with 5 movement joystick</li></ul><p><br></p>', '<ul><li>U-ფორმის საკრეჭი აპარატი ავტომატური ცენტრირების სისტემით</li><li>მინიმალური გახსნა: 40 სმ</li><li>მაქსიმალური გახსნა: 110 სმ</li><li>სიმაღლის რეგულირება: 102 სმ</li><li>ელექტრული მართვა კაბინიდან— 5-მოძრაობიანი ჯოისტიკით</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/ba771523-1c58-484c-a7c1-0c679c967a53.webp', 'https://youtu.be/m_uprbj1ls0', NULL, false, '2025-11-10T10:13:04.096741+00:00', '2025-11-12T12:19:54.122025+00:00', 'u-shaped-pruning-machine-fama', 'u-phormis-sakreji-mankana', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/6198a0e2-4401-4798-b797-146a0a188f1d.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('054be25b-08bb-42b2-8ff0-ab5b69f600cb', NULL, 'Ideal spryer Alpine with tower', 'Alpine-საწამლი ', '<ul><li>Available with or without tower</li><li>Trailed version from 600 to 800 liters</li><li>Circuit-rinsing device</li><li>Fan with 700 diameter</li></ul>', '<p>ხელმისაწვდომია პირამიდით ან პირამიდის გარეშე</p><p> მისაბმელი ვერსია – 600-დან 800 ლიტრამდე</p><p> სისტემის გამრეცხი მოწყობილობა</p><ul><li> ვენტილატორი – დიამეტრი 700</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/9dac3dfd-49fc-46c3-b306-6f186e1d011e.webp', 'https://youtu.be/j4OIWo080YM', NULL, false, '2025-11-11T10:59:33.267782+00:00', '2025-11-12T12:25:29.957219+00:00', 'ideal-spryer-alpine-with-tower', 'ideal-spryer-alpine', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/13f3b430-19b7-4fbc-b0a8-7cb21d7dd73b.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('87bfbfa9-1da5-4bb8-80e2-d4b12002a2aa', '922727df-6a6a-43d2-b5b8-7a29c752214e', 'Windrower for prunings', 'Fama- ს ვინდროუერი (ნარჩენების შეკრებისთვის)', '<ul><li>Opening headboard vine runner windrowers</li><li>Head hoisting</li><li>Right arm hoisting (in order to make easier the transport of the machine) </li><li>Left arm hoisting (in order to make easier the transport of the machine)</li></ul>', '<ul><li>გახსნადი (რეგურილებადი) შემკრები როტორები</li><li>წინა და უკანა გადახრის რეგურილება</li><li>მარჯვენა მკლავის ამწევა (მექანიზმის ტრანსპორტის გამარტივებისთვის)</li><li>მარცხენა მკლავის ამწევა (მექანიზმის ტრანსპორტის გამარტივებისთვის)</li></ul><p><br></p>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/b6158e50-ac04-491f-aa8c-c9e81d52b50a.webp', 'https://www.facebook.com/watch/?v=195596178004249', NULL, false, '2025-11-06T09:14:30.573122+00:00', '2025-11-10T10:35:58.13496+00:00', 'windrower-for-prunings', 'fama-s-vindroueri-narchenebis-shekrebisthvis', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/82a7b7b6-62a6-4153-91cf-b6906a404661.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('767f08ad-bb95-432a-a439-e4150b0052ef', NULL, 'Mulcher TFB medium duty', 'TFB საშუალო სიმძლავრის მულჩერი', '<ul><li>Heavy duty mulcher</li><li>Helical cutting system</li><li>Available in different sizes: from 1.2 to 3.0 meters</li><li>Low body height (only 50cm) suitable for vineyard</li><li>Can cut prunings up to 5 cm</li></ul><p><br></p>', '<ul><li>მაღალი გამძლეობის მულჩერი</li><li>სპირალური (ჰელიკური) ჭრის სისტემა</li><li>ხელმისაწვდომია სხვადასხვა ზომით: 1.2-დან 3.0 მეტრამდე</li><li>დაბალი კორპუსის სიმაღლე – მხოლოდ 50 სმ, იდეალურია ვენახისთვის</li><li>გასხვლის შემდგომი ნარჩენები 5 სმ-მდე დიამეტრით</li></ul><p><br></p>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/0abca103-c3df-40a1-97c3-f16e44e03dd5.webp', 'https://youtu.be/rpJN05QsPJU', NULL, false, '2025-11-10T10:46:58.424236+00:00', '2025-11-10T10:46:58.424236+00:00', 'mulcher-tfb-medium-duty', NULL, '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/bb6bc679-67b6-4986-811e-4227f3f135da.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('13b1b3e4-bf2e-4da5-85f1-29589cb09000', '9c4776ab-9235-4817-84b0-7ab17c478cc3', 'Mulcher with IT hidraulic disk', 'საბაღე და სავენახე  მულჩერი IT ჰიდრავლიკური დისკით', '<ul><li>Available in different sizes: from 1.3 to 2.0 meters</li><li>Can cut grass and prunings up to 5cm</li><li>Lateral mechanical movement</li><li>Disk to cut grass between trees</li><li>Hydraulic sensor to recognize trees</li></ul>', '<ul><li>ხელმისაწვდომია სხვადასხვა ზომაში: 1.3-დან 2.0 მეტრამდე</li><li>აქუცმაცებს ბალახს და დატოტვებს 5 სმ-მდე</li><li>გვერდითი მექანიკური გადაადგილება</li><li>დისკი მწკრივთა შორის ბალახის გასათიბად</li><li>ხეების ამომცნობი ჰიდრავლიკური სენსორი</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/23da22ec-4ff2-4470-9a44-77fea8805e92.webp', 'https://youtu.be/pUgMjyv042w', NULL, false, '2025-11-05T17:21:55.237228+00:00', '2025-11-12T12:28:44.564293+00:00', 'mulcher-with-it-hidraulic-disk', 'sabaghe-da-savenakhe-mulcheri-it', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/d1194cd0-5681-4734-b9d8-4341a5c20037.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('6f2bc57e-40c1-43fa-b039-fb0d5bf4ba01', '922727df-6a6a-43d2-b5b8-7a29c752214e', 'Ideal inter-row herbicide bar', 'ideal -ჰერბიციდის შემტანი', '<p>Herbicide bar with pneumatic sensor to detect trees</p><p>Automatic hydraulic opening of the arms up to 6 meters</p><p>Full control of movements from tractor cabin</p><p>Tank capacity from 600 liters to 3 tons</p><p>On request: mechanic boom for inter-row weed control of the complete row</p>', '<ul><li>ჰერბიციდის შემტანი პნევმატური სენსორით ხეების ამოსაცნობად</li><li>მკლავების ავტომატური ჰიდრავლიკური გახსნა 6 მეტრამდე</li><li>მოძრაობების სრული კონტროლი ტრაქტორის სალონიდან</li><li>მოცულობა: 600 ლიტრიდან 3 ტონამდე</li><li>მოთხოვნის შემთხვევაში: მექანიკური მკლავი რიგთაშორის ბალახის შესაწამლად</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/79ed8557-6be0-455e-a603-6cb258230576.webp', 'https://www.youtube.com/shorts/li7FUb2KCr8?feature=share', NULL, false, '2025-11-06T11:03:54.376531+00:00', '2025-11-10T12:11:01.722721+00:00', 'ideal-inter-row-herbicide-bar', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('873dc63d-7946-4e7c-9db7-14acfbaae7d8', 'c19629da-f41c-4ffd-b835-3cf06a643579', 'Ideal Spryer rhone - rhone top', 'ideal Rhone  შესაწამლი აპარატი', '<ul><li>Trapezoidal fan reverse with reverse aspiration</li><li>Mounted version available from 400 to 600 liters</li><li>Trailed version available from 1000 to 3000 liters</li><li>Brass self-cleaning filters</li><li>Centrifugal clutch</li></ul>', '<ul><li>ტრაპეციული ფორმის კოშკური ვენტილატორი — <strong>ასპირაციის სისტემით</strong></li><li>ასაკიდებელი ვერსია — მოცულობა <strong>400-დან 600 ლიტრამდე</strong></li><li>მისაბმელი ვერსია — მოცულობა <strong>1000-დან 3000 ლიტრამდე</strong></li><li>თვითწმენდის თითბერის ფილტრები</li><li>ცენტრიდანული გადაბმულობა</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/f2338748-ec31-437d-b04d-d6acac0cdcb0.webp', 'https://youtu.be/aPKCi03MCvQ', NULL, false, '2025-11-06T10:16:13.660829+00:00', '2025-11-11T09:14:30.082133+00:00', 'ideal-spryer-rhone-rhone-top', 'rhone-tipis-mimphrkvevi-spreieri', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/91b2f926-6594-43e6-8fa7-b70cc9492629.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('2e94f16e-517b-4522-b101-1d5460d139af', NULL, 'Inter-row tool carrier CST', 'მწკრივთა შორის დამუშავება', '<ul><li>Rear attachment to the tractor</li><li>Complete with independent hydraulic system</li><li>Possibility of setting up more than 25 tools</li><li>Multi-function joystick for adjustment management</li><li>Hydraulic side shift opening/closing and tool adjustment</li></ul><p><br></p>', '<ul><li>ტრაქტორის უკანა ნაწილზე სამაგრი</li><li>მოყვება დამოუკიდებელი ჰიდრავლიკური სისტემა</li><li>შესაძლებელია 25-ზე მეტი სამუშაო აგრეგატის დაყენება</li><li>მრავალფუნქციური ჯოისტიკი რეგულირებების მართვისთვის</li><li>ჰიდრავლიკური გვერდითი გადაადგილება, გახსნა/დახურვა და იარაღების პოზიციონირება</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/11ebf282-998a-47c3-b3e3-89ec4e15a159.webp', 'https://youtu.be/F2-AC3MkyQQ', NULL, false, '2025-11-10T10:52:04.93902+00:00', '2025-11-12T12:29:36.642281+00:00', 'inter-row-tool-carrier-cst', 'mtsenaretha-shoris-damushaveba', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/4c46033c-4e6d-4ed2-8180-c2024aa80fe1.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/373f6adc-93bb-4f77-a63f-77bab58221c7.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/24066f6e-aaa7-45fc-ab36-8d08c038b4f2.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/55f17d7f-405a-4521-baba-8e47eee92425.webp"]', NULL, NULL, N