INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('beb6796e-5630-4f3e-a746-6e4a33ca779d', '9c4776ab-9235-4817-84b0-7ab17c478cc3', 'Salf grass cutter', 'სალფის-ბალახის სათიბელა', '<p>Salf mower grass cutter</p><ul><li>Equipped with two expandable inter-row arms</li><li>Reach different inter-row widths and are equipped with respectively 2,3,4 rotors</li><li>Mower with parallelogram lateral movement</li></ul>', '<p>Salf-ის ბალახის სათიბი მანქანა</p><p>აღჭყრვილია მეწკრივთა შორის სათიბელებით (ორმხრივი)</p><p>დანებზე ან ჭაჭვებზე მომუშავე მულჩერით</p><p>,გვერდითი გადაადგილებით</p>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/f7a84b2e-5bf5-41a6-8f64-3d608b46ce3a.webp', 'https://youtu.be/aHmG32hwZ5Q', NULL, false, '2025-11-06T08:55:59.95214+00:00', '2025-11-12T12:39:23.107039+00:00', 'salf-grass-cutter', 'salf-grass-cutter', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/246b5b07-2f41-4bf8-a48c-f57231417adf.webp"]', NULL, '<p>Options available:</p><ul><li>Bilateral weeding kit</li><li>Hydraulic sensors for disc retraction</li></ul>', '<p>ხელმისაწვდომი დამატებითი ობციები:</p><p>ორმხრივი სარეველა ნაკრების სისტემა</p><ul><li> დისკის გაწევის ჰიდრავლიკური სენსორები</li></ul><p><br></p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('8e2f4631-7398-432a-aa98-4993effdde8c', NULL, 'Second-hand grape harvesters', '(მეორადი) მოსავლის ამღები ტექნიკა', '<p>Second-hand grape harvesters with possibility of full refurbishment:</p><p>Different brands available:</p><ul><li>Pellenc</li><li>ERO</li><li>New Holland</li><li>Gregoire</li><li>Imeca</li><li>Braud</li></ul><p><br></p><p>Transport, delivery, installation and training included in Georgia</p><p><br></p><p>Included 6 months or 1 year warranty</p>', '<p>მეორადი ყურძნის მოსაკრეფი კომბაინები სრული აღდგენის შესაძლებლობით:</p><p>ხელმისაწვდომია სხვადასხვა ბრენდი:</p><ul><li><strong>Pellenc</strong></li><li><strong>ERO</strong></li><li><strong>New Holland</strong></li><li><strong>Gregoire</strong></li><li><strong>Imeca</strong></li><li><strong>Braud</strong></li></ul><p>ტრანსპორტირება, მიწოდება, მონტაჟი და ტრენინგი შედის ფასში საქართველოს ტერიტორიაზე.</p><p>მოყვება <strong>6 თვის ან 1 წლის გარანტია</strong>.</p>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/9274bf59-de2c-4e88-b6d5-6810ab5917a4.webp', NULL, NULL, false, '2025-11-11T12:31:22.554342+00:00', '2025-11-12T12:42:29.490893+00:00', 'second-hand-grape-harvesters', 'meoradi-venaxis-mosavlis-amgebi', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.products (id, category_id, name_en, name_ka, description_en, description_ka, specs_en, specs_ka, image_url, video_url, price, is_featured, created_at, updated_at, slug_en, slug_ka, gallery_image_urls, related_product_ids, additional_info_en, additional_info_ka, video_description_en, video_description_ka, name_ru, description_ru, slug_ru, additional_info_ru, video_description_ru, specs_ru) VALUES ('ad0c1e8c-d4a1-4077-ac91-42f0abba9e1f', NULL, 'Grape harvesters', 'ვენახის მოსახლის ამღები', '<ul><li>Tractor requirement: 70 HP</li><li>Traction-wheels with hydraulic transmission</li><li>Electro-hydraulic control</li><li>Little space requirement </li><li>Up to 5 hectares per hour</li><li>Automatic unloading system</li></ul>', '<ul><li>ტრაქტორის მახასიათებელი: 70 ცხენის ძალა</li><li>ბორბლები ჰიდრავლიკური გადაცემით</li><li>ელექტრო-ჰიდრავლიკური მართვა</li><li>კომპაქტური ზომები, მცირე სივრცის მოთხოვნით</li><li>საშუალოდ 5 ჰექტარი საათში</li><li>ავტომატური გადამტვირთავი სისტემა</li></ul>', NULL, NULL, 'https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/main/3a8b798a-388b-497c-b0c7-3505b63e100c.webp', 'https://youtu.be/TQ5uxDA1Ksg', NULL, false, '2025-11-11T12:23:17.640284+00:00', '2025-11-12T12:42:55.732174+00:00', 'grape-harvesters', 'venakhis-mosakhlis-amghebi', '["https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/eb308c65-921a-4412-b67a-403d74c03400.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/04c4032c-51cd-4dae-9667-a618a9f65ff5.webp","https://qkocoxnnrecilxuzmkpf.supabase.co/storage/v1/object/public/assets/products/gallery/1b5cd102-5a76-47ff-9de8-7ba8ea94ae36.webp"]', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (id) DO NOTHING;
