INSERT INTO public.success_stories (id, title_en, title_ka, slug_en, slug_ka, excerpt_en, excerpt_ka, content_en, content_ka, featured_image_url, gallery_image_urls, customer_name_en, customer_name_ka, customer_location_en, customer_location_ka, customer_company, customer_testimonial_en, customer_testimonial_ka, product_ids, results_achieved, publish_date, is_published, is_featured, meta_title_en, meta_title_ka, meta_description_en, meta_description_ka, view_count, created_at, updated_at, title_ru, slug_ru, excerpt_ru, content_ru, customer_name_ru, customer_location_ru, customer_testimonial_ru, meta_title_ru, meta_description_ru) VALUES ('9d69de9c-4eb5-4c7a-9993-c0bb326139ca', 'NUTS INCORPORATED ', '„ნათს ინკორპორეითედი“', 'nuts-incorporated', 'nuts-incorporated', 'cleaning, hulling and drying line for almonds, capacity 4 tons per hour installed in 2024', 'საწმენდი და საშრობი ხაზი ნუშისთვის. წარმდაბოთ - 4 ტონა საათში', 'Nuts Incorporated, a main producer of almonds and hazelnuts in Georgia, has recently done significant strategic investments aimed at strengthening its position in the global nuts market. The acquisition from Agroit of a new almond cracking line and the purchase of ten self-propelled harvesters represents more than just equipment upgrades. Nuts Incorporated owns and manages approximately 3,100 hectares of orchards in total, with a significant 2,500 hectares dedicated to thriving hazelnut cultivation in Western Georgia. 800 hectares of almonds are located in Eastern Georgia.
INSERT INTO public.success_stories (id, title_en, title_ka, slug_en, slug_ka, excerpt_en, excerpt_ka, content_en, content_ka, featured_image_url, gallery_image_urls, customer_name_en, customer_name_ka, customer_location_en, customer_location_ka, customer_company, customer_testimonial_en, customer_testimonial_ka, product_ids, results_achieved, publish_date, is_published, is_featured, meta_title_en, meta_title_ka, meta_description_en, meta_description_ka, view_count, created_at, updated_at, title_ru, slug_ru, excerpt_ru, content_ru, customer_name_ru, customer_location_ru, customer_testimonial_ru, meta_title_ru, meta_description_ru) VALUES ('67bfa255-26a4-434e-96f8-f55315dc4acb', 'Nikora Supermarket', '„ნიკორა სუპერმარკეტი“', 'nikora-supermarket', 'nikora-supermarket', 'Nikora Supermarket invested, with Agroit support, in a new calibration machine for potatoes and onions and a fully automatic packaging line from the Italian company Sorma. This step forward reshaped Nikora’s fresh market operations, reinforcing its commitment to quality, efficiency, and sustainability.', '„ნიკორა სუპერმარკეტმა“, კომპანია „აგროიტ“-ის მხარდაჭერით, განახორციელა ინვესტიცია ბოსტნეულის — კარტოფილისა და ხახვის — ახალი კალიბრაციის დანადგარში და იტალიური კომპანია Sorma-ს სრულად ავტომატიზებულ შესაფუთ ხაზში. აღნიშნული ნაბიჯი წარმოადგენს მნიშვნელოვან წინსვლას „ნიკორას“ ახალი პროდუქტების ოპერაციებში, რაც კიდევ ერთხელ უსვამს ხაზს კომპანიის ერთგულებას ხარისხის, ეფექტიანობისა და მდგრადი განვითარების პრინციპებისადმი.
